import numpy as np

def recommend_encoding(data_type, n_samples, n_features, max_qubits, max_depth, task):
    # Decision logic based on constraints

    if data_type == 'discrete' and task == 'search':
        qubits_needed = int(np.ceil(np.log2(n_samples)))
        if qubits_needed <= max_qubits:
            return ('basis', 'Discrete data + search task = basis encoding for quantum search')

    if task == 'inner_product':
        qubits_needed = int(np.ceil(np.log2(n_features)))
        if qubits_needed <= max_qubits and n_features <= max_depth:
            return ('amplitude', 'Inner product task benefits from amplitude encoding overlap')

    if task == 'classification':
        # Check if kernel is feasible (O(N²) kernel matrix)
        if n_samples <= 100 and n_features <= max_qubits:
            return ('kernel_zz', f'Small dataset ({n_samples} samples) makes kernel method feasible')

        # Otherwise use angle encoding
        if n_features <= max_qubits and max_depth >= 1:
            return ('angle_parallel', 'Angle encoding for variational classification')
        elif max_depth >= n_features:
            return ('angle_sequential', 'Sequential angle when qubits limited')

    # Default fallback
    if n_features <= max_qubits:
        return ('angle_parallel', 'Default to simple angle encoding')
    else:
        return ('angle_sequential', 'Sequential angle for qubit-limited case')

test_cases = [
    ('discrete', 100, 5, 10, 50, 'search'),
    ('continuous', 50, 8, 8, 20, 'classification'),
    ('continuous', 1000, 4, 4, 100, 'inner_product'),
    ('continuous', 20, 6, 6, 5, 'classification')
]

for args in test_cases:
    enc, reason = recommend_encoding(*args)
    print(f'{args}')
    print(f'  -> {enc}')
    print(f'  Reason: {reason}\n')
